 46→    }
 47→
 48→    pub fn new_with_diff(
 49→        tags: Vec<DicomTag>,
 50→        file_name: String,
 51→        modified_name: Option<String>,
 52→        validation_result: ValidationResult,
 53→        sop_class: SopClass,
 54→        diff_mode: bool,
 55→    ) -> Self {
 56→        let mut table_state = TableState::default();
 57→        let visible_tags = Self::build_visible_tags_from(&tags);
 58→        if !visible_tags.is_empty() {
 59→            table_state.select(Some(0));
 60→        }
 61→
 62→        Self {
 63→            tags: visible_tags,
 64→            all_tags: tags,
 65→            filtered_tags: None,
 66→            table_state,
 67→            should_quit: false,
 68→            file_name,
 69→            diff_mode,
 70→            modified_name,
 71→            search_mode: false,
 72→            search_query: String::new(),
 73→            validation_result,
 74→            sop_class,
 75→            table_area: Rect::default(),
 76→        }
 77→    }
 78→
 79→    fn build_visible_tags_from(tags: &[DicomTag]) -> Vec<DicomTag> {
 80→        let mut visible = Vec::new();
 81→        Self::collect_visible_tags(tags, &mut visible);
 82→        visible
 83→    }
 84→
 85→    fn collect_visible_tags(tags: &[DicomTag], visible: &mut Vec<DicomTag>) {
 86→        for tag in tags {
 87→            visible.push(tag.clone());
 88→            if tag.is_expanded && !tag.children.is_empty() {
 89→                Self::collect_visible_tags(&tag.children, visible);
 90→            }
 91→        }
 92→    }
 93→
 94→    fn rebuild_visible_tags(&mut self) {
 95→        // Use filtered_tags if a search filter is active, otherwise use all_tags
 96→        let source = self.filtered_tags.as_ref().unwrap_or(&self.all_tags);
 97→        self.tags = Self::build_visible_tags_from(source);
 98→    }
 99→
100→    /// Returns the hierarchical tag source for path operations
101→    fn active_tags(&self) -> &Vec<DicomTag> {
102→        self.filtered_tags.as_ref().unwrap_or(&self.all_tags)
103→    }
104→
105→    /// Returns mutable hierarchical tag source for modifications
106→    fn active_tags_mut(&mut self) -> &mut Vec<DicomTag> {
107→        if self.filtered_tags.is_some() {
108→            self.filtered_tags.as_mut().unwrap()
109→        } else {
110→            &mut self.all_tags
111→        }
112→    }
113→
114→    fn expand_selected(&mut self) {
115→        if let Some(selected_idx) = self.table_state.selected() {
116→            if selected_idx < self.tags.len() {
117→                let selected_tag = &self.tags[selected_idx];
118→                if selected_tag.is_expandable && !selected_tag.is_expanded {
119→                    let path = self.build_path_to_tag(selected_idx);
120→                    Self::set_expanded_in_tree(self.active_tags_mut(), &path, true);
121→                    self.rebuild_visible_tags();
122→                }
123→            }
124→        }
125→    }
126→
127→    fn collapse_parent(&mut self) {
128→        if let Some(selected_idx) = self.table_state.selected() {
129→            if selected_idx < self.tags.len() {
130→                let current_depth = self.tags[selected_idx].depth;
131→
132→                if current_depth > 0 {
133→                    for i in (0..selected_idx).rev() {
134→                        if self.tags[i].depth < current_depth && self.tags[i].is_expanded {
135→                            let path = self.build_path_to_tag(i);
136→                            Self::set_expanded_in_tree(self.active_tags_mut(), &path, false);
137→                            self.rebuild_visible_tags();
138→                            self.table_state.select(Some(i));
139→                            break;
140→                        }
141→                    }
142→                }
143→            }
144→        }
145→    }
146→
147→    fn build_path_to_tag(&self, visible_idx: usize) -> Vec<usize> {
148→        let mut path = Vec::new();
149→        let mut current_idx = 0;
150→        Self::find_path_to_index(self.active_tags(), visible_idx, &mut current_idx, &mut path);
151→        path
152→    }
153→
154→    fn find_path_to_index(
155→        tags: &[DicomTag],
156→        target_idx: usize,
157→        current_idx: &mut usize,
158→        path: &mut Vec<usize>,
159→    ) -> bool {
160→        for (i, tag) in tags.iter().enumerate() {
161→            if *current_idx == target_idx {
162→                path.push(i);
163→                return true;
164→            }
165→            *current_idx += 1;
166→
167→            if tag.is_expanded && !tag.children.is_empty() {
168→                path.push(i);
169→                if Self::find_path_to_index(&tag.children, target_idx, current_idx, path) {
170→                    return true;
171→                }
172→                path.pop();
173→            }
174→        }
175→        false
176→    }
177→
178→    fn set_expanded_in_tree(tags: &mut [DicomTag], path: &[usize], expanded: bool) {
179→        if path.is_empty() {
180→            return;
181→        }
182→
183→        let idx = path[0];
184→        if idx >= tags.len() {
185→            return;
186→        }
187→
188→        if path.len() == 1 {
189→            tags[idx].is_expanded = expanded;
190→        } else {
191→            Self::set_expanded_in_tree(&mut tags[idx].children, &path[1..], expanded);
192→        }
193→    }
194→
195→    pub fn handle_events(&mut self) -> io::Result<()> {
196→        if event::poll(std::time::Duration::from_millis(100))? {
197→            match event::read()? {
198→                Event::Key(key) if key.kind == KeyEventKind::Press => {
199→                    if self.search_mode {
200→                        match key.code {
201→                            KeyCode::Esc => {
202→                                self.search_mode = false;
203→                                self.search_query.clear();
204→                                self.filtered_tags = None;
205→                                self.rebuild_visible_tags();
206→                                self.reset_selection();
207→                            }
208→                            KeyCode::Enter => {
209→                                self.search_mode = false;
210→                            }
211→                            KeyCode::Backspace => {
212→                                self.search_query.pop();
213→                                self.filter_tags();
214→                            }
215→                            KeyCode::Char(c) => {
216→                                self.search_query.push(c);
217→                                self.filter_tags();
218→                            }
219→                            _ => {}
220→                        }
221→                    } else {
222→                        match key.code {
223→                            KeyCode::Char('q') | KeyCode::Esc => {
224→                                if self.search_query == "" {
225→                                    self.should_quit = true;
226→                                } else {
227→                                    self.search_query.clear();
228→                                    self.filtered_tags = None;
229→                                    self.rebuild_visible_tags();
230→                                    self.reset_selection();
231→                                }
232→                            }
233→                            KeyCode::Down | KeyCode::Char('j') => {
234→                                self.scroll_down(1);
235→                            }
236→                            KeyCode::Up | KeyCode::Char('k') => {
237→                                self.scroll_up(1);
238→                            }
239→                            KeyCode::Char('/') => {
240→                                self.search_mode = true;
241→                            }
242→                            KeyCode::Right | KeyCode::Char('l') => {
243→                                self.expand_selected();
244→                            }
245→                            KeyCode::Left | KeyCode::Char('h') => {
246→                                self.collapse_parent();
247→                            }
248→                            _ => {}
249→                        }
250→                    }
251→                }
252→                Event::Mouse(mouse) => match mouse.kind {
253→                    MouseEventKind::ScrollDown => self.scroll_down(3),
254→                    MouseEventKind::ScrollUp => self.scroll_up(3),
255→                    MouseEventKind::Down(MouseButton::Left) => {
256→                        let y = mouse.row;
257→                        if y > self.table_area.y + 1
258→                            && y < self.table_area.y + self.table_area.height
259→                        {
260→                            let row_in_viewport = (y - self.table_area.y - 2) as usize;
261→                            let tag_index = self.table_state.offset() + row_in_viewport;
262→                            if tag_index < self.tags.len() {
263→                                self.table_state.select(Some(tag_index));
264→                            }
265→                        }
266→                    }
267→                    _ => {}
268→                },
269→                _ => {}
270→            }
271→        }
272→        Ok(())
273→    }
274→
275→    fn scroll_down(&mut self, amount: usize) {
276→        if self.tags.is_empty() {
277→            return;
278→        }
279→
280→        let current = self.table_state.selected().unwrap_or(0);
281→        let max_index = self.tags.len().saturating_sub(1);
282→        let new_index = (current + amount).min(max_index);
283→        self.table_state.select(Some(new_index));
284→    }
285→
286→    fn scroll_up(&mut self, amount: usize) {
287→        if self.tags.is_empty() {
288→            return;
289→        }
290→
291→        let current = self.table_state.selected().unwrap_or(0);
292→        let new_index = current.saturating_sub(amount);
293→        self.table_state.select(Some(new_index));
294→    }
295→
296→    fn filter_tags(&mut self) {
297→        if self.search_query.is_empty() {
298→            self.filtered_tags = None;
299→            self.rebuild_visible_tags();
300→        } else {
301→            let query = self.search_query.to_lowercase();
302→            // Filter top-level tags but preserve their full hierarchy (children)
303→            let filtered: Vec<DicomTag> = self
304→                .all_tags
305→                .iter()
306→                .filter(|tag| {
307→                    tag.tag.to_lowercase().contains(&query)
308→                        || tag.name.to_lowercase().contains(&query)
309→                })
310→                .cloned()
311→                .collect();
312→            self.filtered_tags = Some(filtered);
313→            self.rebuild_visible_tags();
314→        }
315→        self.reset_selection();
316→    }
317→
318→    fn reset_selection(&mut self) {
319→        if self.tags.is_empty() {
320→            self.table_state.select(None);
321→        } else {
322→            self.table_state.select(Some(0));
323→        }
324→    }
325→}
