fn center_image_rect(area: Rect, app: &App) -> Rect {
    let Some((img_w, img_h)) = app.preview_image_size else {
        return area;
    };
    let Some(picker) = &app.picker else {
        return area;
    };
    let (fw, fh) = picker.font_size();
    if fw == 0 || fh == 0 || img_w == 0 || img_h == 0 {
        return area;
    }

    let avail_px_w = area.width as u32 * fw as u32;
    let avail_px_h = area.height as u32 * fh as u32;

    let scale = f64::min(
        avail_px_w as f64 / img_w as f64,
        avail_px_h as f64 / img_h as f64,
    );
    let fitted_w_cells = ((img_w as f64 * scale) / fw as f64).ceil() as u16;
    let fitted_h_cells = ((img_h as f64 * scale) / fh as f64).ceil() as u16;

    let w = fitted_w_cells.min(area.width);
    let h = fitted_h_cells.min(area.height);
    let x = area.x + (area.width.saturating_sub(w)) / 2;
    let y = area.y + (area.height.saturating_sub(h)) / 2;

    Rect::new(x, y, w, h)
}

