                    DiffStatus::Added => (
                        Style::default().fg(Color::Green),
                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Green)),
                    ),
                    DiffStatus::Changed => {
                        // Use inline diff if baseline_value is available
                        let value_cell = if let Some(ref baseline) = tag.baseline_value {
                            let mut line = render_inline_diff(baseline, &tag.value);
                            if let Some(delta_ms) =
                                parse_dicom_datetime_delta_ms(&tag.vr, baseline, &tag.value)
                            {
                                let suffix = if delta_ms >= 0 {
                                    format!(" (+{} ms)", delta_ms)
                                } else {
                                    format!(" ({} ms)", delta_ms)
                                };
                                line.spans.push(Span::styled(
                                    suffix,
                                    Style::default().fg(Color::DarkGray),
                                ));
                            }
                            Cell::from(line)
                        } else {
                            // Fallback to simple blue text for backward compatibility
                            Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Blue))
                        };
                        (Style::default(), value_cell)
                    }
                    DiffStatus::Unchanged => (
                        Style::default(),
                        Cell::from(tag.value.as_str()).style(Style::default()),
                    ),
                }
            } else {
                // Normal mode: use private tag styling
                let base_style = if tag.is_private() {
                    Style::default().fg(Color::DarkGray)
                } else {
                    Style::default()
                };
                (base_style, Cell::from(tag.value.as_str()).style(base_style))
            };

            let mut row_cells = vec![];

            // Add diff indicator if in diff mode
            if app.diff_mode {
                let (indicator, indicator_style) = if let Some(diff_status) = &tag.diff_status {
                    match diff_status {
                        DiffStatus::Added => ("+", Style::default().fg(Color::Green)),
                        DiffStatus::Deleted => ("-", Style::default().fg(Color::Red)),
                        DiffStatus::Changed => ("M", Style::default().fg(Color::Blue)),
                        DiffStatus::Unchanged => (" ", Style::default()),
                    }
                } else {
                    (" ", Style::default())
                };
                row_cells.push(Cell::from(indicator).style(indicator_style));
            }

            row_cells.extend(vec![
                Cell::from(tag_display).style(row_style),
                Cell::from(tag.name.as_str()).style(row_style),
                Cell::from(tag.vr.as_str()).style(row_style),
                value_cell,
            ]);

            Row::new(row_cells)
        })
        .collect();

    let widths: Vec<Constraint> = if app.diff_mode {
        vec![
            Constraint::Length(1),
            Constraint::Length(16),
            Constraint::Length(36),
            Constraint::Length(4),
            Constraint::Fill(1),
        ]
    } else {
        vec![
            Constraint::Length(16),
            Constraint::Length(36),
            Constraint::Length(4),
            Constraint::Fill(1),
        ]
    };

    let title = if app.diff_mode {
        if let Some(ref modified_name) = app.modified_name {
            format!(" DICOM Diff: {} ↔ {} ", app.file_name, modified_name)
        } else {
            format!(" DICOM Diff: {} ", app.file_name)
        }
    } else {
        format!(" DICOM Viewer: {} ", app.file_name)
    };

    let table = Table::new(rows, widths)
        .header(header)
        .block(Block::default().borders(Borders::ALL).title(title))
        .row_highlight_style(
            Style::default()
                .bg(Color::DarkGray)
                .add_modifier(Modifier::BOLD),
        );

    app.table_area = area;
    frame.render_stateful_widget(table, area, &mut app.table_state);

    render_help(frame, area, app);
}

fn render_inline_diff(baseline: &str, modified: &str) -> Line<'static> {
    let diff = TextDiff::from_words(baseline, modified);
    let mut spans = Vec::new();

    for change in diff.iter_all_changes() {
        let text = change.value();
        let style = match change.tag() {
            ChangeTag::Delete => Style::default()
                .fg(Color::Red)
                .bg(Color::DarkGray)
                .add_modifier(Modifier::CROSSED_OUT),
            ChangeTag::Insert => Style::default()
                .fg(Color::Green)
                .add_modifier(Modifier::BOLD),
            ChangeTag::Equal => Style::default(),
        };
        spans.push(Span::styled(text.to_string(), style));
    }

    Line::from(spans)
}

fn render_help(frame: &mut Frame, area: Rect, app: &App) {
    let help_area = Rect {
        x: area.x + 1,
        y: area.y + area.height.saturating_sub(1),
        width: area.width.saturating_sub(2),
        height: 1,
    };

    if app.search_mode {
        let search_text = format!("/{}_", app.search_query);
        let search = Paragraph::new(search_text).style(Style::default().fg(Color::Yellow));
        frame.render_widget(search, help_area);
    } else {
        let help_text = " ↑/↓: Navigate | →: Expand | ←: Collapse | /: Search | p: Preview | q/Esc: Quit ";
        let help = Paragraph::new(help_text).style(Style::default().fg(Color::Cyan));
        frame.render_widget(help, help_area);
    }
}

fn render_preview_pane(frame: &mut Frame, area: Rect, app: &mut App) {
    let block = Block::default()
        .borders(Borders::ALL)
        .title(" Preview ");

    if let Some(ref error) = app.preview_error {
        let paragraph = Paragraph::new(error.as_str())
            .style(Style::default().fg(Color::Red))
            .block(block);
        frame.render_widget(paragraph, area);
    } else if let Some(ref mut protocol) = app.preview_image {
        let inner = block.inner(area);
        frame.render_widget(block, area);
        let image = StatefulImage::new(None);
        frame.render_stateful_widget(image, inner, protocol);
    } else {
        let paragraph = Paragraph::new("Decoding...")
            .style(Style::default().fg(Color::DarkGray))
            .block(block);
        frame.render_widget(paragraph, area);
    }
}

fn render_validation_pane(frame: &mut Frame, area: Rect, app: &App) {
    let sop_class_text = match &app.sop_class {
        SopClass::Ct => "CT Image Storage",
        SopClass::Mr => "MR Image Storage",
        SopClass::Other(_) => "Other",
        SopClass::Unknown => "Unknown",
    };

    let sop_class_uid = match &app.sop_class {
        SopClass::Ct => "1.2.840.10008.5.1.4.1.1.2",
        SopClass::Mr => "1.2.840.10008.5.1.4.1.1.4",
        SopClass::Other(uid) => uid.as_str(),
        SopClass::Unknown => "N/A",
    };

    let (title, border_color) = match &app.validation_result {
        ValidationResult::Valid => (" ✓ All required fields present ", Color::Blue),
        ValidationResult::Invalid(_) => (" ✗ Missing required fields ", Color::Red),
        ValidationResult::NotApplicable => (" Validation not applicable ", Color::DarkGray),
    };

    let mut lines = vec![Line::from(vec![Span::raw(format!(
        "SOP Class: {} ({})",
        sop_class_text, sop_class_uid
    ))])];

    if let ValidationResult::Invalid(missing) = &app.validation_result {
        let missing_text = missing.join(", ");
        lines.push(Line::from(vec![
            Span::styled("Missing:   ", Style::default().fg(Color::Red)),
            Span::styled(
                missing_text,
                Style::default().fg(Color::Red).add_modifier(Modifier::BOLD),
            ),
        ]));
    }

    let paragraph = Paragraph::new(lines).block(
        Block::default()
            .borders(Borders::ALL)
            .border_style(Style::default().fg(border_color))
            .title(title)
            .title_style(Style::default().fg(border_color)),
    );

    frame.render_widget(paragraph, area);
}

use crate::dicom::DicomTag;
use crate::validation::{SopClass, ValidationResult};
use crossterm::event::{self, Event, KeyCode, KeyEventKind, MouseButton, MouseEventKind};
use ratatui::layout::Rect;
use ratatui::widgets::TableState;
use ratatui_image::picker::Picker;
use ratatui_image::protocol::StatefulProtocol;
use std::io;
use std::path::PathBuf;

/// Application state
pub struct App {
    /// Visible tags to display (flattened based on expansion state)
    pub tags: Vec<DicomTag>,
    /// All unfiltered DICOM tags (hierarchical)
    pub all_tags: Vec<DicomTag>,
    /// Filtered top-level tags when search is active (hierarchical, preserves children)
    filtered_tags: Option<Vec<DicomTag>>,
    /// Table state for tracking selection/scroll position
    pub table_state: TableState,
    /// Whether the application should quit
    pub should_quit: bool,
    /// The file name being viewed (or baseline name in diff mode)
    pub file_name: String,
    /// Whether diff mode is active
    pub diff_mode: bool,
    /// Modified file name in diff mode
    pub modified_name: Option<String>,
    /// Whether search mode is active
    pub search_mode: bool,
    /// Current search query
    pub search_query: String,
    /// Type 1 field validation result
    pub validation_result: ValidationResult,
    /// SOP Class interpretation
    pub sop_class: SopClass,
    pub table_area: Rect,
    pub show_preview: bool,
    pub preview_image: Option<StatefulProtocol>,
    pub preview_image_size: Option<(u32, u32)>,
    pub preview_error: Option<String>,
    pub dicom_file_path: Option<PathBuf>,
    pub picker: Option<Picker>,
}

impl App {
    pub fn new_with_diff(
        tags: Vec<DicomTag>,
        file_name: String,
        modified_name: Option<String>,
        validation_result: ValidationResult,
        sop_class: SopClass,
        diff_mode: bool,
        dicom_file_path: Option<PathBuf>,
        picker: Option<Picker>,
    ) -> Self {
        let mut table_state = TableState::default();
        let visible_tags = Self::build_visible_tags_from(&tags);
        if !visible_tags.is_empty() {
            table_state.select(Some(0));
        }

        let mut app = Self {
            tags: visible_tags,
            all_tags: tags,
            filtered_tags: None,
            table_state,
            should_quit: false,
            file_name,
            diff_mode,
            modified_name,
            search_mode: false,
            search_query: String::new(),
            validation_result,
            sop_class,
            table_area: Rect::default(),
            show_preview: true,
            preview_image: None,
            preview_image_size: None,
            preview_error: None,
            dicom_file_path,
            picker,
        };
        app.decode_preview();
        app
    }

    fn build_visible_tags_from(tags: &[DicomTag]) -> Vec<DicomTag> {
        let mut visible = Vec::new();
        Self::collect_visible_tags(tags, &mut visible);
        visible
    }

    fn collect_visible_tags(tags: &[DicomTag], visible: &mut Vec<DicomTag>) {
        for tag in tags {
            visible.push(tag.clone());
            if tag.is_expanded && !tag.children.is_empty() {
                Self::collect_visible_tags(&tag.children, visible);
            }
        }
    }

    fn rebuild_visible_tags(&mut self) {
        // Use filtered_tags if a search filter is active, otherwise use all_tags
        let source = self.filtered_tags.as_ref().unwrap_or(&self.all_tags);
        self.tags = Self::build_visible_tags_from(source);
    }

    /// Returns the hierarchical tag source for path operations
    fn active_tags(&self) -> &Vec<DicomTag> {
        self.filtered_tags.as_ref().unwrap_or(&self.all_tags)
    }

    /// Returns mutable hierarchical tag source for modifications
    fn active_tags_mut(&mut self) -> &mut Vec<DicomTag> {
        if self.filtered_tags.is_some() {
            self.filtered_tags.as_mut().unwrap()
        } else {
            &mut self.all_tags
        }
    }

    fn expand_selected(&mut self) {
        if let Some(selected_idx) = self.table_state.selected() {
            if selected_idx < self.tags.len() {
                let selected_tag = &self.tags[selected_idx];
                if selected_tag.is_expandable && !selected_tag.is_expanded {
                    let path = self.build_path_to_tag(selected_idx);
                    Self::set_expanded_in_tree(self.active_tags_mut(), &path, true);
                    self.rebuild_visible_tags();
                }
            }
        }
    }

    fn collapse_parent(&mut self) {
        if let Some(selected_idx) = self.table_state.selected() {
            if selected_idx < self.tags.len() {
                let current_depth = self.tags[selected_idx].depth;

                if current_depth > 0 {
                    for i in (0..selected_idx).rev() {
                        if self.tags[i].depth < current_depth && self.tags[i].is_expanded {
                            let path = self.build_path_to_tag(i);
                            Self::set_expanded_in_tree(self.active_tags_mut(), &path, false);
                            self.rebuild_visible_tags();
                            self.table_state.select(Some(i));
                            break;
                        }
                    }
                }
            }
        }
    }

    fn build_path_to_tag(&self, visible_idx: usize) -> Vec<usize> {
        let mut path = Vec::new();
        let mut current_idx = 0;
        Self::find_path_to_index(self.active_tags(), visible_idx, &mut current_idx, &mut path);
        path
    }

    fn find_path_to_index(
        tags: &[DicomTag],
        target_idx: usize,
        current_idx: &mut usize,
        path: &mut Vec<usize>,
    ) -> bool {
        for (i, tag) in tags.iter().enumerate() {
            if *current_idx == target_idx {
                path.push(i);
                return true;
            }
            *current_idx += 1;

            if tag.is_expanded && !tag.children.is_empty() {
                path.push(i);
                if Self::find_path_to_index(&tag.children, target_idx, current_idx, path) {
                    return true;
                }
                path.pop();
            }
        }
        false
    }

    fn set_expanded_in_tree(tags: &mut [DicomTag], path: &[usize], expanded: bool) {
        if path.is_empty() {
            return;
        }

        let idx = path[0];
        if idx >= tags.len() {
            return;
        }

        if path.len() == 1 {
            tags[idx].is_expanded = expanded;
        } else {
            Self::set_expanded_in_tree(&mut tags[idx].children, &path[1..], expanded);
        }
    }

    pub fn handle_events(&mut self) -> io::Result<()> {
        if event::poll(std::time::Duration::from_millis(100))? {
            match event::read()? {
                Event::Key(key) if key.kind == KeyEventKind::Press => {
                    if self.search_mode {
                        match key.code {
                            KeyCode::Esc => {
                                self.search_mode = false;
                                self.search_query.clear();
                                self.filtered_tags = None;
                                self.rebuild_visible_tags();
                                self.reset_selection();
                            }
                            KeyCode::Enter => {
                                self.search_mode = false;
                            }
                            KeyCode::Backspace => {
                                self.search_query.pop();
                                self.filter_tags();
                            }
                            KeyCode::Char(c) => {
                                self.search_query.push(c);
                                self.filter_tags();
                            }
                            _ => {}
                        }
                    } else {
                        match key.code {
                            KeyCode::Char('q') | KeyCode::Esc => {
                                if self.search_query == "" {
                                    self.should_quit = true;
                                } else {
                                    self.search_query.clear();
                                    self.filtered_tags = None;
                                    self.rebuild_visible_tags();
                                    self.reset_selection();
                                }
                            }
                            KeyCode::Down | KeyCode::Char('j') => {
                                self.scroll_down(1);
                            }
                            KeyCode::Up | KeyCode::Char('k') => {
                                self.scroll_up(1);
                            }
                            KeyCode::Char('/') => {
                                self.search_mode = true;
                            }
                            KeyCode::Char('p') => {
                                self.toggle_preview();
                            }
                            KeyCode::Right | KeyCode::Char('l') => {
                                self.expand_selected();
                            }
                            KeyCode::Left | KeyCode::Char('h') => {
                                self.collapse_parent();
                            }
                            _ => {}
                        }
                    }
                }
                Event::Mouse(mouse) => match mouse.kind {
                    MouseEventKind::ScrollDown => self.scroll_down(3),
                    MouseEventKind::ScrollUp => self.scroll_up(3),
                    MouseEventKind::Down(MouseButton::Left) => {
                        let y = mouse.row;
                        if y > self.table_area.y + 1
                            && y < self.table_area.y + self.table_area.height
                        {
                            let row_in_viewport = (y - self.table_area.y - 2) as usize;
                            let tag_index = self.table_state.offset() + row_in_viewport;
                            if tag_index < self.tags.len() {
                                self.table_state.select(Some(tag_index));
                            }
                        }
                    }
                    _ => {}
                },
                _ => {}
            }
        }
        Ok(())
    }

    fn scroll_down(&mut self, amount: usize) {
        if self.tags.is_empty() {
            return;
        }

        let current = self.table_state.selected().unwrap_or(0);
        let max_index = self.tags.len().saturating_sub(1);
        let new_index = (current + amount).min(max_index);
        self.table_state.select(Some(new_index));
    }

    fn scroll_up(&mut self, amount: usize) {
        if self.tags.is_empty() {
            return;
        }

        let current = self.table_state.selected().unwrap_or(0);
        let new_index = current.saturating_sub(amount);
        self.table_state.select(Some(new_index));
    }

    fn filter_tags(&mut self) {
        if self.search_query.is_empty() {
            self.filtered_tags = None;
            self.rebuild_visible_tags();
        } else {
            let query = self.search_query.to_lowercase();
            // Filter top-level tags but preserve their full hierarchy (children)
            let filtered: Vec<DicomTag> = self
                .all_tags
                .iter()
                .filter(|tag| {
                    tag.tag.to_lowercase().contains(&query)
                        || tag.name.to_lowercase().contains(&query)
                })
                .cloned()
                .collect();
            self.filtered_tags = Some(filtered);
            self.rebuild_visible_tags();
        }
        self.reset_selection();
    }

    fn reset_selection(&mut self) {
        if self.tags.is_empty() {
            self.table_state.select(None);
        } else {
            self.table_state.select(Some(0));
        }
    }

    fn toggle_preview(&mut self) {
        self.show_preview = !self.show_preview;

        if self.show_preview && self.preview_image.is_none() && self.preview_error.is_none() {
            self.decode_preview();
        }
    }

    fn decode_preview(&mut self) {
        use dicom_pixeldata::PixelDecoder;
        use ratatui_image::picker::ProtocolType;

        let Some(picker) = &self.picker else {
            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
            return;
        };

        if picker.protocol_type() != ProtocolType::Kitty {
            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
            return;
        }

        let Some(path) = &self.dicom_file_path else {
            self.preview_error = Some("No DICOM file path available".into());
            return;
        };

        let obj = match dicom::object::open_file(path) {
            Ok(obj) => obj,
            Err(e) => {
                self.preview_error = Some(format!("Failed to open DICOM file: {}", e));
                return;
            }
        };

        let pixel_data = match obj.decode_pixel_data() {
            Ok(pd) => pd,
            Err(e) => {
                self.preview_error = Some(format!("Failed to decode pixel data: {}", e));
                return;
            }
        };

        let dyn_img = match pixel_data.to_dynamic_image(0) {
            Ok(img) => img,
            Err(e) => {
                self.preview_error = Some(format!("Failed to convert to image: {}", e));
                return;
            }
        };

        self.preview_image_size = Some((dyn_img.width(), dyn_img.height()));
        let mut picker = self.picker.take().unwrap();
        self.preview_image = Some(picker.new_resize_protocol(dyn_img));
        self.picker = Some(picker);
    }
}

